package operators;

public class Ternaryoperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//ternary operator works like if-else statement
		//first it checks the condition if the condition is true then it returns a value otherwise it returns b value
		int a=3;
		int b=4;
		System.out.println((a>b)?a:b);

	}

}
